import 'package:cryptography_utils/cryptography_utils.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/functions/abi_function_definition.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/functions/abi_param_definition.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_address_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_bool_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_bytes_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_dynamic_array_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_int_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_static_array_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_string_type.dart';
import 'package:cryptography_utils/src/encoder/generic_encoder/abi/solidity_types/solidity_tuple_type.dart';
import 'package:test/test.dart';

void main() {
  AbiFunctionDefinition actualAbiFunctionDefinition = AbiFunctionDefinition(
    name: 'test_function',
    inputs: <AbiParamDefinition>[
      AbiParamDefinition(
        name: 'address',
        type: SolidityAddressType(),
      ),
      AbiParamDefinition(
        name: 'bool',
        type: SolidityBoolType(),
      ),
      AbiParamDefinition(
        name: 'bytes',
        type: SolidityBytesType(),
      ),
      AbiParamDefinition(
        name: 'dynamic_array',
        type: SolidityDynamicArrayType('uint256[]'),
      ),
      AbiParamDefinition(
        name: 'int',
        type: SolidityIntType('uint256'),
      ),
      AbiParamDefinition(
        name: 'static_array',
        type: SolidityStaticArrayType('uint256[9]'),
      ),
      AbiParamDefinition(
        name: 'string',
        type: SolidityStringType(),
      ),
      AbiParamDefinition(
        name: 'tuple',
        type: SolidityTupleType(
          <AbiParamDefinition>[
            AbiParamDefinition(name: 'address', type: SolidityAddressType()),
            AbiParamDefinition(name: 'bool', type: SolidityBoolType()),
            AbiParamDefinition(name: 'bytes', type: SolidityBytesType()),
            AbiParamDefinition(name: 'dynamic_array', type: SolidityDynamicArrayType('int256[]')),
            AbiParamDefinition(name: 'int', type: SolidityIntType('int256')),
            AbiParamDefinition(name: 'static_array', type: SolidityStaticArrayType('int256[9]')),
            AbiParamDefinition(name: 'string', type: SolidityStringType()),
            AbiParamDefinition(
              name: 'nested_tuple',
              type: SolidityTupleType(<AbiParamDefinition>[
                AbiParamDefinition(name: 'address', type: SolidityAddressType()),
                AbiParamDefinition(name: 'bool', type: SolidityBoolType()),
                AbiParamDefinition(name: 'bytes', type: SolidityBytesType()),
                AbiParamDefinition(name: 'dynamic_array', type: SolidityDynamicArrayType('int256[]')),
                AbiParamDefinition(name: 'int', type: SolidityIntType('int256')),
                AbiParamDefinition(name: 'static_array', type: SolidityStaticArrayType('int256[9]')),
                AbiParamDefinition(name: 'string', type: SolidityStringType())
              ]),
            )
          ],
        ),
      ),
    ],
  );

  group('Tests of AbiFunctionDefinition.decodeParameters()', () {
    test('Should [return decoded function parameters] from given bytes', () {
      // Arrange
      List<int> actualBytes = HexEncoder.decode(
          '');

      // Act
      Map<String, dynamic> actualFunctionParams = actualAbiFunctionDefinition.decodeParameters(actualBytes);

      // Assert
      Map<String, dynamic> expectedFunctionParams = <String, dynamic>{
        'address': '0x53bf0a18754873a8102625d8225af6a15a43423c',
        'bool': true,
        'bytes': <int>[1, 2, 3, 4, 5, 6, 7, 8, 9],
        'dynamic_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
        'int': '1234',
        'static_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
        'string': 'Hello World!',
        'tuple': <String, dynamic>{
          'address': '0x53bf0a18754873a8102625d8225af6a15a43423c',
          'bool': true,
          'bytes': <int>[1, 2, 3, 4, 5, 6, 7, 8, 9],
          'dynamic_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
          'int': '1234',
          'static_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
          'string': 'Hello World!',
          'nested_tuple': <String, dynamic>{
            'address': '0x53bf0a18754873a8102625d8225af6a15a43423c',
            'bool': true,
            'bytes': <int>[1, 2, 3, 4, 5, 6, 7, 8, 9],
            'dynamic_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
            'int': '1234',
            'static_array': <String>['1', '2', '3', '4', '5', '6', '7', '8', '9'],
            'string': 'Hello World!'
          }
        }
      };

      expect(actualFunctionParams, expectedFunctionParams);
    });
  });

  group('Tests of AbiFunctionDefinition.functionSelector getter ', () {
    test('Should [return function selector] for given AbiFunctionDefinition', () {
      // Act
      String actualFunctionSelector = actualAbiFunctionDefinition.functionSelector;

      // Assert
      String expectedFunctionSelector = 'fff7f391';

      expect(actualFunctionSelector, expectedFunctionSelector);
    });
  });

  group('Tests of AbiFunctionDefinition.functionSignature getter ', () {
    test('Should [return function signature] for given AbiFunctionDefinition', () {
      // Act
      String actualFunctionSignature = actualAbiFunctionDefinition.functionSignature;

      // Assert
      String expectedFunctionSignature = 'test_function(address,bool,bytes,uint256[],uint256,uint256[9],string,tuple)';

      expect(actualFunctionSignature, expectedFunctionSignature);
    });
  });
}
